  /* в”Җв”Җв”Җ и®°еҝҶжЁЎеқ— в”Җв”Җв”Җ */
  function shouldAttachMemory() { return Math.random() * 100 < (state.settings.memoryAttachProbability || 30); }
  function loadMountedMemories(cb) {
    var ids = state.settings.mountedConversationIds || [];
    if (ids.length === 0) { cb(""); return; }
    var MAX_FACTS = 5;
    var parts = [], done = 0;
    for (var i = 0; i < ids.length; i++) {
      (function(cid) {
        state.roche.memory.getLongTerm({ conversationId: cid, limit: 50 }).then(function(lt) {
          var coreText = (lt.core && lt.core.summary) || "";
          var allFacts = (lt.facts || []).map(function(f) { return f.summaryText || f.action || f.text || ""; }).filter(Boolean);
          var shuffled = allFacts.sort(function() { return Math.random() - 0.5; });
          var pickedFacts = shuffled.slice(0, MAX_FACTS);
          var factText = pickedFacts.join("\n");
          var combined = [coreText, factText].filter(Boolean).join("\n");
          debugLog("mem cid:" + cid + " core:" + (coreText ? "Y" : "N") + " facts:" + allFacts.length + "->" + pickedFacts.length);
          if (combined) parts.push(combined);
          done++; if (done === ids.length) cb(parts.join("\n\n"));
        }).catch(function() { done++; if (done === ids.length) cb(parts.join("\n\n")); });
      })(ids[i]);
    }
  }

  /* в”Җв”Җв”Җ AI жөҒејҸи°ғз”Ё в”Җв”Җв”Җ */
  function extractDeltaText(dataStr) {
    try {
      var parsed = JSON.parse(dataStr);
      if (parsed.choices && parsed.choices[0]) {
        var d = parsed.choices[0].delta;
        if (d && d.content) return d.content;
      }
      if (parsed.type === "content_block_delta" && parsed.delta) {
        if (parsed.delta.text) return parsed.delta.text;
      }
      if (parsed.text) return parsed.text;
      if (parsed.content && typeof parsed.content === "string") return parsed.content;
    } catch(e) {
      /* JSONдёҚе®Ңж•ҙпјҢе°қиҜ•зӣҙжҺҘжҸҗеҸ–contentеӯ—ж®ө */
      var contentMatch = dataStr.match(/"content"\s*:\s*"((?:[^"\\]|\\.)*)"/);
      if (contentMatch) {
        try { return JSON.parse('"' + contentMatch[1] + '"'); } catch(e2) {}
      }
    }
    return null;
  }

  function aiChatStream(messages, temperature, onProgress, onDone, onError) {
    var _done = false;
    var _stallTimer = null;
    var _lastContentLen = 0;
    var _debugChunkCount = 0;
    var _fallbackUsed = false;
    var readerRef = null;

    function finish(raw) {
      if (_done) return;
      _done = true;
      clearTimeout(_stallTimer);
      onDone(raw);
    }
    function fail(e) {
      if (_done) return;
      _done = true;
      clearTimeout(_stallTimer);
      if (onError) onError(e); else onDone("");
    }

    function resetStallTimer() {
      clearTimeout(_stallTimer);
      /* еҰӮжһң180з§’еҶ…fullContentжІЎжңүеўһй•ҝпјҢи§ҶдёәеҒңж»һпјҢfallbackеҲ°йқһжөҒејҸ */
      _stallTimer = setTimeout(function() {
        if (_fallbackUsed || _done) return;
        debugLog("stream: stall detected (no new content for 180s), falling back to non-stream");
        _fallbackUsed = true;
        try { if (readerRef) readerRef.cancel(); } catch(e) {}
        doNonStreamFallback();
      }, 180000);
    }

    function doNonStreamFallback() {
      debugLog("falling back to non-stream");
      state.roche.ai.chat({ messages: messages, temperature: temperature }).then(function(r) {
        var raw = (r && typeof r === "string") ? r : (r && r.text) ? r.text : String(r || "");
        debugLog("non-stream fallback got len:" + raw.length);
        finish(raw);
      }).catch(function(e2) { debugLog("non-stream fallback err:" + (e2&&e2.message?e2.message:String(e2))); fail(e2); });
    }

    try {
      var chatPromise = state.roche.ai.chat({ messages: messages, temperature: temperature, stream: true });
    } catch(e) {
      debugLog("stream: sync error on call, fallback non-stream");
      doNonStreamFallback();
      return;
    }
    chatPromise.then(function(response) {
      debugLog("stream resp type:" + typeof response + " keys:" + (response ? Object.keys(response).join(",") : "null"));
      var body = response && (response.body || response.stream);
      if (body && typeof body.getReader === "function") {
        var reader = body.getReader();
        readerRef = reader;
        var decoder = new TextDecoder();
        var fullContent = "";
        var rawBuffer = "";
        resetStallTimer();
        function pump() {
          reader.read().then(function(result) {
            if (result.done) {
              debugLog("stream done, content len:" + fullContent.length);
              finish(fullContent);
              return;
            }
            var chunk = decoder.decode(result.value, { stream: true });
            _debugChunkCount++;
            if (_debugChunkCount <= 5) {
              debugLog("stream chunk #" + _debugChunkCount + " len:" + chunk.length + " preview:" + chunk.substring(0, 200));
            }
            /* жҜҸж”¶еҲ°chunkйғҪйҮҚзҪ®stall timerвҖ”вҖ”иҝһжҺҘиҝҳжҙ»зқҖ */
            resetStallTimer();
            rawBuffer += chunk;
            /* д»ҺrawBufferдёӯжҸҗеҸ–жүҖжңүе®Ңж•ҙзҡ„data:иЎҢ */
            var searchFrom = 0;
            while (true) {
              var dataStart = rawBuffer.indexOf("data: ", searchFrom);
              if (dataStart < 0) break;
              var nextData = rawBuffer.indexOf("\ndata: ", dataStart + 6);
              var lineEnd = rawBuffer.indexOf("\n", dataStart + 6);
              if (nextData < 0 && lineEnd < 0) {
                /* dataиЎҢдёҚе®Ңж•ҙпјҢдҝқз•ҷеҲ°bufferзӯүжӣҙеӨҡж•°жҚ® */
                searchFrom = dataStart;
                break;
              }
              var endPos = nextData >= 0 ? nextData : (lineEnd >= 0 ? lineEnd : rawBuffer.length);
              var dataStr = rawBuffer.substring(dataStart + 6, endPos).trim();
              if (dataStr === "[DONE]") {
                searchFrom = endPos + 1;
                continue;
              }
              var text = extractDeltaText(dataStr);
              if (text !== null) {
                fullContent += text;
                if (onProgress) onProgress(fullContent);
              }
              searchFrom = endPos + 1;
            }
            /* дҝқз•ҷжңӘеӨ„зҗҶзҡ„йғЁеҲҶ */
            if (searchFrom > 0) rawBuffer = rawBuffer.substring(searchFrom);
            /* еҒңж»һжЈҖжөӢ */
            if (fullContent.length > _lastContentLen) {
              _lastContentLen = fullContent.length;
              resetStallTimer();
            }
            pump();
          }).catch(function(e) {
            debugLog("stream read err:" + e.message + ", content len:" + fullContent.length);
            finish(fullContent);
          });
        }
        pump();
      } else {
        debugLog("stream: no getReader, extracting text directly");
        var raw = "";
        if (typeof response === "string") raw = response;
        else if (response && response.text && typeof response.text === "string") raw = response.text;
        else if (response && typeof response.text === "function") {
          response.text().then(function(t) { debugLog("resp.text() len:" + t.length); finish(t); }).catch(function(e) { fail(e); });
          return;
        } else {
          debugLog("stream: unknown resp format, keys:" + Object.keys(response || {}).join(","));
          raw = JSON.stringify(response);
        }
        debugLog("direct extract len:" + raw.length);
        finish(raw);
      }
    }).catch(function(e) {
      debugLog("stream chat err:" + (e && e.message ? e.message : String(e)) + ", fallback non-stream");
      doNonStreamFallback();
    });
  }

  function stripXmlAndExtractJson(raw) {
    var macroChain = "";
    var macroMatch = raw.match(/<macro_chain>([\s\S]*?)<\/macro_chain>/i);
    if (macroMatch) macroChain = macroMatch[1].trim();
    var stripped = raw.replace(/<inline_check>[\s\S]*?<\/inline_check>/gi, "")
      .replace(/<macro_cot>[\s\S]*?<\/macro_cot>/gi, "")
      .replace(/<macro_chain>[\s\S]*?<\/macro_chain>/gi, "")
      .replace(/<inline_chain>[\s\S]*?<\/inline_chain>/gi, "")
      .replace(/<core_philosophy>[\s\S]*?<\/core_philosophy>/gi, "")
      .replace(/<knowledge_base>[\s\S]*?<\/knowledge_base>/gi, "")
      .replace(/<output_protocol>[\s\S]*?<\/output_protocol>/gi, "")
      .replace(/<inline_check_system>[\s\S]*?<\/inline_check_system>/gi, "")
      .replace(/<system_execution_directive>[\s\S]*?<\/system_execution_directive>/gi, "")
      .replace(/<!--[\s\S]*?-->/g, "")
      .replace(/<[^>]+>/g, "");
    /* е°қиҜ•еҢ№й…Қе®Ңж•ҙJSON */
    var m = stripped.match(/\{[\s\S]*\}/);
    if (m) return { json: m[0], macroChain: macroChain };
    /* JSONиў«жҲӘж–ӯпјҡе°қиҜ•жүҫеҲ°з¬¬дёҖдёӘ { е№¶иЎҘе…Ёй—ӯеҗҲжӢ¬еҸ· */
    var firstBrace = stripped.indexOf("{");
    if (firstBrace < 0) return { json: null, macroChain: macroChain };
    var partial = stripped.substring(firstBrace);
    /* и®Ўз®—жңӘй—ӯеҗҲзҡ„жӢ¬еҸ·ж•°йҮҸе№¶иЎҘе…Ё */
    var openBraces = 0, openBrackets = 0, inStr = false, escape = false;
    for (var ci = 0; ci < partial.length; ci++) {
      var ch = partial[ci];
      if (escape) { escape = false; continue; }
      if (ch === "\\") { if (inStr) escape = true; continue; }
      if (ch === '"') { inStr = !inStr; continue; }
      if (inStr) continue;
      if (ch === "{") openBraces++;
      else if (ch === "}") openBraces--;
      else if (ch === "[") openBrackets++;
      else if (ch === "]") openBrackets--;
    }
    /* еҰӮжһңеңЁеӯ—з¬ҰдёІдёӯиў«жҲӘж–ӯпјҢе…Ҳе…ій—ӯеӯ—з¬ҰдёІ */
    if (inStr) partial += '"';
    /* иЎҘе…ЁзјәеӨұзҡ„й—ӯеҗҲжӢ¬еҸ· */
    while (openBrackets > 0) { partial += "]"; openBrackets--; }
    while (openBraces > 0) { partial += "}"; openBraces--; }
    debugLog("JSON truncated, repaired by adding closing brackets");
    return { json: partial, macroChain: macroChain };
  }

  /* в”Җв”Җв”Җ иҮӘе®ҡд№үжЁЎеһӢ API и°ғз”Ё в”Җв”Җв”Җ */
  function getActiveModelPreset() {
    var s = state.settings;
    if (!s.modelPresets || s.modelPresets.length === 0 || !s.activeModelPresetId) return null;
    for (var i = 0; i < s.modelPresets.length; i++) {
      if (s.modelPresets[i].id === s.activeModelPresetId) return s.modelPresets[i];
    }
    return null;
  }

  function customAiChat(messages, temperature, onProgress, onDone, onError) {
    var preset = getActiveModelPreset();
    if (!preset || !preset.apiUrl || !preset.apiKey || !preset.model) {
      if (onError) onError(new Error("жңӘй…ҚзҪ®иҪ»еһӢжЁЎеһӢйў„и®ҫ"));
      return;
    }
    var url = preset.apiUrl.replace(/\/+$/, "") + "/v1/chat/completions";
    var body = JSON.stringify({ model: preset.model, messages: messages, temperature: temperature, stream: true });
    var controller = new AbortController();
    var _done = false;
    var fullContent = "";
    var TIMEOUT_MS = 120000; /* 2еҲҶй’ҹи¶…ж—¶ */
    var timeoutId = setTimeout(function() {
      debugLog("customAiChat timeout after " + TIMEOUT_MS + "ms, model:" + preset.model);
      controller.abort();
      if (fullContent.length > 0) {
        /* и¶…ж—¶дҪҶжңүйғЁеҲҶеҶ…е®№пјҢиҝ”еӣһе·ІиҺ·еҸ–зҡ„еҶ…е®№ */
        finish(fullContent);
      } else {
        fail(new Error("иҜ·жұӮи¶…ж—¶пјҲ" + (TIMEOUT_MS/1000) + "з§’пјүпјҢжЁЎеһӢпјҡ" + preset.model));
      }
    }, TIMEOUT_MS);

    function finish(raw) { if (_done) return; _done = true; clearTimeout(timeoutId); onDone(raw); }
    function fail(e) { if (_done) return; _done = true; clearTimeout(timeoutId); if (onError) onError(e); else onDone(""); }

    fetch(url, {
      method: "POST",
      headers: { "Content-Type": "application/json", "Authorization": "Bearer " + preset.apiKey },
      body: body,
      signal: controller.signal
    }).then(function(resp) {
      if (!resp.ok) {
        debugLog("customAiChat: API error " + resp.status);
        resp.text().then(function(t) { fail(new Error("API " + resp.status + ": " + t.substring(0, 200))); }).catch(function() { fail(new Error("API " + resp.status)); });
        return;
      }
      /* жЈҖжҹҘжҳҜеҗҰдёәжөҒејҸе“Қеә” */
      var contentType = resp.headers.get("content-type") || "";
      debugLog("customAiChat: response content-type=" + contentType);
      var isStreamResponse = contentType.indexOf("text/event-stream") >= 0 || contentType.indexOf("stream") >= 0;
      if (isStreamResponse) {
        /* жөҒејҸе“Қеә” */
        var reader;
        try {
          reader = resp.body.getReader();
        } catch(readerErr) {
          debugLog("customAiChat: getReader() failed, falling back to non-stream: " + readerErr.message);
          /* ж— жі•иҺ·еҸ–readerпјҢеӣһйҖҖеҲ°йқһжөҒејҸиҜ»еҸ– */
          resp.text().then(function(t) {
            debugLog("customAiChat: fallback text read, len=" + t.length);
            fullContent = t;
            if (onProgress) onProgress(fullContent);
            finish(fullContent);
          }).catch(function(e2) { fail(e2); });
          return;
        }
        var decoder = new TextDecoder();
        var rawBuffer = "";

        function pump() {
          try {
            reader.read().then(function(result) {
              if (result.done) { finish(fullContent); return; }
              var chunk = decoder.decode(result.value, { stream: true });
              rawBuffer += chunk;
              var lines = rawBuffer.split("\n");
              rawBuffer = lines.pop();
              for (var i = 0; i < lines.length; i++) {
                var line = lines[i].trim();
                if (line.indexOf("data: ") !== 0) continue;
                var dataStr = line.substring(6);
                if (dataStr === "[DONE]") { finish(fullContent); return; }
                var delta = extractDeltaText(dataStr);
                if (delta) { fullContent += delta; if (onProgress) onProgress(fullContent); }
              }
              pump();
            }).catch(function(e) {
              debugLog("customAiChat: stream read error: " + (e && e.message ? e.message : String(e)));
              /* жөҒиҜ»еҸ–еӨұиҙҘпјҢеҰӮжһңжңүйғЁеҲҶеҶ…е®№еҲҷиҝ”еӣһ */
              if (fullContent.length > 0) { finish(fullContent); }
              else { fail(e); }
            });
          } catch(pumpErr) {
            debugLog("customAiChat: pump() exception: " + pumpErr.message);
            if (fullContent.length > 0) { finish(fullContent); }
            else { fail(pumpErr); }
          }
        }
        pump();
      } else {
        /* йқһжөҒејҸе“Қеә”пјҲжҹҗдәӣиҪ»еһӢжЁЎеһӢAPIдёҚж”ҜжҢҒstreamпјү */
        debugLog("customAiChat: non-stream response detected, content-type=" + contentType + ", reading as JSON");
        resp.json().then(function(data) {
          var text = "";
          if (data.choices && data.choices[0] && data.choices[0].message) {
            text = data.choices[0].message.content || "";
          } else if (data.content && typeof data.content === "string") {
            text = data.content;
          } else if (data.text) {
            text = data.text;
          } else if (typeof data === "string") {
            text = data;
          }
          debugLog("customAiChat: non-stream parsed OK, text len=" + text.length);
          fullContent = text;
          if (onProgress) onProgress(fullContent);
          finish(fullContent);
        }).catch(function(e) {
          debugLog("customAiChat: JSON parse failed, trying plain text: " + e.message);
          /* JSONи§ЈжһҗеӨұиҙҘпјҢе°қиҜ•зәҜж–Үжң¬ */
          resp.text().then(function(t) {
            fullContent = t;
            if (onProgress) onProgress(fullContent);
            finish(fullContent);
          }).catch(function(e2) { fail(e2); });
        });
      }
    }).catch(function(e) {
      debugLog("customAiChat: fetch error: " + (e && e.message ? e.message : String(e)));
      fail(e);
    });
  }

  function fetchModelList(apiUrl, apiKey, callback) {
    var url = apiUrl.replace(/\/+$/, "") + "/v1/models";
    fetch(url, {
      method: "GET",
      headers: { "Authorization": "Bearer " + apiKey }
    }).then(function(resp) {
      if (!resp.ok) { callback(null, "API " + resp.status); return; }
      return resp.json();
    }).then(function(data) {
      if (!data || !data.data) { callback(null, "иҝ”еӣһж јејҸејӮеёё"); return; }
      var models = [];
      for (var i = 0; i < data.data.length; i++) {
        if (data.data[i].id) models.push(data.data[i].id);
      }
      models.sort();
      callback(models, null);
    }).catch(function(e) { callback(null, e.message || "иҜ·жұӮеӨұиҙҘ"); });
  }

  function testModelPreset(apiUrl, apiKey, model, callback) {
    var url = apiUrl.replace(/\/+$/, "") + "/v1/chat/completions";
    fetch(url, {
      method: "POST",
      headers: { "Content-Type": "application/json", "Authorization": "Bearer " + apiKey },
      body: JSON.stringify({ model: model, messages: [{ role: "user", content: "Hi" }], max_tokens: 5 }),
      signal: AbortSignal.timeout(15000)
    }).then(function(resp) {
      if (!resp.ok) { resp.text().then(function(t) { callback(false, "API " + resp.status + ": " + t.substring(0, 100)); }).catch(function() { callback(false, "API " + resp.status); }); return; }
      callback(true, "иҝһжҺҘжҲҗеҠҹ");
    }).catch(function(e) { callback(false, e.message || "иҝһжҺҘеӨұиҙҘ"); });
  }

  /* в”Җв”Җв”Җ AI и°ғз”ЁеұӮ в”Җв”Җв”Җ */
  function generateLayer1Summaries(lockTag, callback) {
    try {
    debugLog("L1 start, cpTags:" + state.cpTags.length + " tropeTags:" + state.tropeTags.length);
    var cpTags = state.cpTags;
    if (cpTags.length > 5) {
      var shuffled = cpTags.slice();
      for (var si = shuffled.length - 1; si > 0; si--) {
        var sj = Math.floor(Math.random() * (si + 1));
        var temp = shuffled[si]; shuffled[si] = shuffled[sj]; shuffled[sj] = temp;
      }
      cpTags = shuffled.slice(0, 5);
    }
    var tropeTags = state.tropeTags, activePersona = state.activePersona;
    if (!cpTags || cpTags.length === 0) { showToast("\u8bf7\u5148\u6dfb\u52a0CP\u6807\u7b7e"); callback(null); return; }
    debugLog("L1 building ctx, cpTags[0] keys:" + (cpTags[0] ? Object.keys(cpTags[0]).join(",") : "null"));
    var targetCount = Math.max(12, cpTags.length * 4);
    var ctx = ["\u8bf7\u751f\u6210 " + targetCount + " \u6761\u540c\u4eba\u6587\u6458\u8981\u3002", "",
      "\u683c\u5f0fJSON\uff1a{ \"summaries\": [{ \"title\":\"\", \"author\":\"\", \"cp\":\"\", \"cpTagId\":\"\", \"warnings\":[], \"summary\":\"\", \"author_note_optional\":\"\", \"tags\":[], \"coverGradient\":\"\", \"likes\":0, \"comments\":0, \"words\":\"\", \"timeAgo\":\"\" }] }", "",
      "\u2501\u2501 \u7528\u6237\u7684\u6240\u6709CP\u914d\u5bf9 \u2501\u2501"];
    for (var i = 0; i < cpTags.length; i++) {
      var tag = cpTags[i];
      var isCpLock = lockTag && lockTag.leftSide;
      if (isCpLock && tag.id !== lockTag.id) continue;
      var left = tag.leftSide || tag.attackSide || {};
      var right = tag.rightSide || tag.defenseSide || {};
      ctx.push("CP #" + (i+1) + ": " + tag.name + " (id:" + tag.id + ")");
      ctx.push("  \u5de6\u4f4d(" + (left.name || "\u672a\u77e5") + "): " + (left.persona || left.bio || "\u65e0\u63cf\u8ff0"));
      ctx.push("  \u53f3\u4f4d(" + (right.name || "\u672a\u77e5") + "): " + (right.persona || right.bio || "\u65e0\u63cf\u8ff0"));
      if (tag.fandomTags && tag.fandomTags.length > 0) ctx.push("  \u2501\u2501 \u5708\u5b50/\u4e16\u754c\u4e66\u8bbe\u5b9a \u2501\u2501\n" + tag.fandomTags.join("\u3001"));
      ctx.push("");
    }
    ctx.push("\u2501\u2501 \u524d\u7aef\u6ce8\u5165\u7684Tag \u2501\u2501");
    var tagStr = "";
    for (var j = 0; j < tropeTags.length; j++) tagStr += (j > 0 ? "\u3001" : "") + tropeTags[j].name;
    ctx.push(tagStr);
    if (activePersona) { ctx.push("", "\u2501\u2501 \u7b2c\u4e09\u89d2\u8272\uff08\u53ef\u4f5c\u4e3a\u53c2\u8003\u4eba\u7269\u6216\u4e92\u52a8\u5bf9\u8c61\uff09 \u2501\u2501", "\u540d\u79f0: " + (activePersona.name || activePersona.handle || "\u672a\u77e5"), "\u4eba\u8bbe: " + (activePersona.persona || activePersona.bio || "")); }

    if (lockTag) {
      var isTropeLock = !lockTag.leftSide;
      if (isTropeLock) {
        ctx.push("", "\u2501\u2501 \u91cd\u8981\uff1a\u672c\u6b21\u53ea\u751f\u6210\u5305\u542b\u6897\u6807\u7b7e\u300c" + lockTag.name + "\u300d\u7684\u6458\u8981 \u2501\u2501");
        ctx.push("\u6bcf\u7bc7\u6458\u8981\u7684 tags \u6570\u7ec4\u4e2d\u5fc5\u987b\u5305\u542b\u300c" + lockTag.name + "\u300d");
        ctx.push("\u8bf7\u786e\u4fdd\u6240\u6709\u6458\u8981\u7684\u5185\u5bb9\u90fd\u56f4\u7ed5\u8fd9\u4e2a\u6897\u5c55\u5f00");
      } else {
        ctx.push("", "\u6ce8\u610f\uff1a\u672c\u6b21\u53ea\u751f\u6210\u5173\u4e8e " + lockTag.name + " \u7684\u6458\u8981");
      }
    }
    debugLog("L1 ctx built, lines:" + ctx.length + " tagStr len:" + tagStr.length);

    var doChat = function(memText) {
      var systemPrompt = PROMPTS.layer1Summary;
      systemPrompt = systemPrompt.replace("[FRONTEND_INJECT_TAGS_HERE]", tagStr);
      var chatMessages = [
        { role: "system", content: systemPrompt },
        { role: "user", content: ctx.join("\n") + (memText ? "\n\n\u3010\u8fd1\u671f\u4e92\u52a8\u8bb0\u5fc6\uff08\u4ec5\u4f9b\u53c2\u8003\u7d20\u6750\uff09\u3011\n" + memText : "") }
      ];
      debugLog("L1 calling aiChatStream, sysLen:" + systemPrompt.length + " usrLen:" + chatMessages[1].content.length);
      aiChatStream(chatMessages, 0.85,
        function(progress) { debugLog("L1 streaming... len:" + progress.length); },
        function(raw) {
          debugLog("L1 stream done, raw len:" + raw.length + " first200:" + raw.substring(0, 200));
          try {
            var extractResult = stripXmlAndExtractJson(raw); var jsonStr = extractResult.json;
            if (!jsonStr) { debugLog("L1 no JSON found"); callback(null); return; }
            var parsed = JSON.parse(jsonStr);
            debugLog("L1 parsed OK, count:" + (parsed.summaries || []).length);
            callback(parsed.summaries || parsed.results || null);
          } catch(e) { debugLog("L1 parse error:" + e.message); callback(null); }
        },
        function(e) { debugLog("L1 stream error:" + (e&&e.message?e.message:String(e))); callback(null); }
      );
    };
    var attachMem = shouldAttachMemory();
    var mountedIds = state.settings.mountedConversationIds || [];
    debugLog("L1 attachMem:" + attachMem + " mountedIds:" + JSON.stringify(mountedIds));
    if (attachMem && mountedIds.length > 0) { debugLog("L1 loading memories..."); loadMountedMemories(function(mt) { debugLog("L1 memories loaded, len:" + mt.length); doChat(mt.substring(0, 3000)); }); } else { debugLog("L1 skipping memory"); doChat(""); }
    } catch(e) { debugLog("L1 FATAL:" + e.message + " stack:" + (e.stack||"").substring(0,300)); callback(null); }
  }

  /* в”Җв”Җв”Җ д»ҺеҺҹе§Ӣж–Үжң¬дёӯжҸҗеҸ–ж®өиҗҪпјҲJSONи§ЈжһҗеӨұиҙҘж—¶зҡ„fallbackпјү в”Җв”Җв”Җ */
  function extractParagraphsFromRaw(raw) {
    var paragraphs = [];
    /* е…Ҳжё…зҗҶXMLж Үзӯҫ */
    var cleaned = raw.replace(/<macro_chain>[\s\S]*?<\/macro_chain>/gi, "")
      .replace(/<inline_check>[\s\S]*?<\/inline_check>/gi, "")
      .replace(/<macro_cot>[\s\S]*?<\/macro_cot>/gi, "")
      .replace(/<inline_chain>[\s\S]*?<\/inline_chain>/gi, "")
      .replace(/<core_philosophy>[\s\S]*?<\/core_philosophy>/gi, "")
      .replace(/<knowledge_base>[\s\S]*?<\/knowledge_base>/gi, "")
      .replace(/<output_protocol>[\s\S]*?<\/output_protocol>/gi, "")
      .replace(/<inline_check_system>[\s\S]*?<\/inline_check_system>/gi, "")
      .replace(/<system_execution_directive>[\s\S]*?<\/system_execution_directive>/gi, "")
      .replace(/<!--[\s\S]*?-->/g, "")
      .replace(/<[^>]+>/g, "");
    /* ж–№жі•1: д»ҺJSONзҡ„"text"еӯ—ж®өжҸҗеҸ– */
    var textParts = cleaned.split(/"text"\s*:\s*"/);
    for (var i = 1; i < textParts.length; i++) {
      var t = textParts[i].replace(/"\s*[,}]\s*$/, "").replace(/\\"/g, '"').replace(/\\n/g, "\n");
      if (t.trim().length > 5) paragraphs.push(t.trim());
    }
    if (paragraphs.length > 0) return paragraphs;
    /* ж–№жі•2: жҢүеҸҢжҚўиЎҢеҲҶеүІпјҢиҝҮж»ӨжҺүJSONз»“жһ„иЎҢ */
    var lines = cleaned.split(/\n/);
    var buffer = "";
    for (var j = 0; j < lines.length; j++) {
      var line = lines[j].trim();
      if (!line || line.indexOf('"') === 0 || line.indexOf('{') === 0 || line.indexOf('}') === 0 ||
          line.indexOf('[') === 0 || line.indexOf(']') === 0 || line.indexOf(':') === 0) {
        if (buffer.trim().length > 10) { paragraphs.push(buffer.trim()); buffer = ""; }
        continue;
      }
      /* и·іиҝҮжҳҺжҳҫзҡ„JSONй”®еҖјиЎҢ */
      if (/^"[a-zA-Z_]+"/.test(line)) { if (buffer.trim().length > 10) { paragraphs.push(buffer.trim()); buffer = ""; } continue; }
      buffer += (buffer ? " " : "") + line;
    }
    if (buffer.trim().length > 10) paragraphs.push(buffer.trim());
    return paragraphs;
  }

  /* в”Җв”Җв”Җ жөҒејҸдёӯж–ӯж—¶зҡ„ fallbackпјҡз”Ёе·ІжҺҘж”¶зҡ„ж®өиҗҪжһ„е»ә fullContent в”Җв”Җв”Җ */
  function _useStreamedFallback(summary, paragraphs, callback) {
    if (!paragraphs || paragraphs.length === 0) {
      debugLog("streamed fallback: no paragraphs, callback null");
      callback(null);
      return;
    }
    debugLog("streamed fallback: building fullContent from " + paragraphs.length + " paragraphs");
    var contentArr = [];
    for (var i = 0; i < paragraphs.length; i++) {
      contentArr.push({ type: "p", text: paragraphs[i].replace(/<br>/g, "\n") });
    }
    var fallbackData = {
      chapter: { title: "", content: contentArr },
      annotations: [],
      continuation_summary: "",
      content_summary: ""
    };
    callback(fallbackData);
  }

  function generateLayer2Full(summary, callback) {
    try {
    debugLog("L2 start, title:" + (summary.title || "?") + " cpTagId:" + (summary.cpTagId || "?"));
    var cpTag = null;
    for (var i = 0; i < state.cpTags.length; i++) { if (state.cpTags[i].id === summary.cpTagId) { cpTag = state.cpTags[i]; break; } }
    if (!cpTag && summary.cpTagName) {
      for (var i2 = 0; i2 < state.cpTags.length; i2++) { if (state.cpTags[i2].name === summary.cpTagName) { cpTag = state.cpTags[i2]; break; } }
    }
    if (!cpTag) {
      debugLog("L2 cpTag not found, using fallback");
      var cpName = summary.cp || summary.cpTagName || "";
      var parts = cpName.split(/\s*[Г—xX]\s*/);
      cpTag = {
        id: summary.cpTagId || "fallback",
        name: cpName,
        leftSide: { id: "f1", name: parts[0] || "\u89d2\u8272A", persona: "" },
        rightSide: { id: "f2", name: parts[1] || "\u89d2\u8272B", persona: "" },
        fandomTags: []
      };
    }
    var left = cpTag.leftSide || cpTag.attackSide || {};
    var right = cpTag.rightSide || cpTag.defenseSide || {};
    debugLog("L2 cpTag found, left:" + (left.name || "?") + " right:" + (right.name || "?"));
    var userMsg = ["\u8bf7\u521b\u4f5c\u4ee5\u4e0b\u540c\u4eba\u6587\u7684\u5b8c\u6574\u5185\u5bb9\uff1a", "",
      "- \u6807\u9898\uff1a" + summary.title, "- CP\uff1a" + (summary.cp || summary.cpTagName || ""),
      "- \u5708\u5b50\uff1a" + (summary.fandomTag || ""), "- \u8bbe\u5b9a/\u6897\uff1a" + (summary.tags ? summary.tags.join(", ") : (summary.tropeTags ? summary.tropeTags.join(", ") : "\u65e0")),
      "- \u6458\u8981\u53c2\u8003\uff1a" + (summary.summary || summary.excerpt || ""), "",
      "\u2501\u2501 \u89d2\u8272\u4eba\u8bbe \u2501\u2501",
      "\u5de6\u4f4d\uff08" + (left.name || "\u672a\u77e5") + "\uff09\uff1a", left.persona || left.bio || "\u65e0\u63cf\u8ff0", "",
      "\u53f3\u4f4d\uff08" + (right.name || "\u672a\u77e5") + "\uff09\uff1a", right.persona || right.bio || "\u65e0\u63cf\u8ff0"].join("\n");
    debugLog("L2 left isPersona:" + !!(left.persona) + " right isPersona:" + !!(right.persona));
    if (cpTag.fandomTags && cpTag.fandomTags.length > 0) {
      userMsg += "\n\n\u2501\u2501 \u5708\u5b50/\u4e16\u754c\u4e66\u8bbe\u5b9a \u2501\u2501\n" + cpTag.fandomTags.join("\u3001");
    }
    if (summary.author_note_optional) userMsg += "\n\u4f5c\u8005\u788e\u788e\u5ff5\uff1a" + summary.author_note_optional;
    if (summary._regenerateFeedback) userMsg += "\n\n\u2501\u2501 \u8bfb\u8005\u53cd\u9988\uff08\u8bf7\u91cd\u70b9\u5173\u6ce8\uff09 \u2501\u2501\n" + summary._regenerateFeedback;

    var wordCountMin = state.settings.wordCountMin || 3000;
    var wordCountMax = state.settings.wordCountMax || 8000;
    var wordCountStr = wordCountMin + "-" + wordCountMax + "\u5b57";
    var promptSrc = (state.settings.promptLanguage === "en" && PROMPTS.layer2FullEN) ? PROMPTS.layer2FullEN : PROMPTS.layer2Full;
    var systemPrompt = promptSrc.replace("[WORD_COUNT_PLACEHOLDER]", wordCountStr);
    debugLog("L2 sysPrompt len:" + systemPrompt.length + " userMsg len:" + userMsg.length);
    summary._debugContext = { systemPrompt: systemPrompt, userMsg: userMsg, memory: null };

    var doChat = function(memText) {
      debugLog("L2 calling aiChatStream, memLen:" + (memText ? memText.length : 0));
      summary._debugContext.memory = memText || "(none)";
      var _streamedParagraphs = []; /* зј“еӯҳжөҒејҸж®өиҗҪпјҢйҳІжӯўдёӯж–ӯдёўеӨұ */
      aiChatStream([
        { role: "system", content: systemPrompt },
        { role: "user", content: userMsg + (memText ? "\n\n\u3010\u8fd1\u671f\u4e92\u52a8\u8bb0\u5fc6\uff08\u4ec5\u4f9b\u53c2\u8003\u7d20\u6750\uff09\u3011\n" + memText : "") }
      ], 0.8,
        function(progress) {
          var spinner = document.getElementById("hp-reader-spinner");
          var streamEl = document.getElementById("hp-reader-stream");
          if (streamEl) {
            if (spinner) spinner.style.display = "none";
            streamEl.style.display = "block";
            var cleaned = progress;
            cleaned = cleaned.replace(/<macro_chain>[\s\S]*?<\/macro_chain>/gi, "");
            cleaned = cleaned.replace(/<inline_chain>[\s\S]*?<\/inline_chain>/gi, "");
            cleaned = cleaned.replace(/<inline_check>[\s\S]*?<\/inline_check>/gi, "");
            cleaned = cleaned.replace(/<macro_cot>[\s\S]*?<\/macro_cot>/gi, "");
            cleaned = cleaned.replace(/<system_execution_directive>[\s\S]*?<\/system_execution_directive>/gi, "");
            cleaned = cleaned.replace(/<!--[\s\S]*?-->/g, "");
            cleaned = cleaned.replace(/<[^>]+>/g, "");
            /* жҸҗеҸ–жүҖжңүж–Үжң¬ж®өиҗҪ */
            var allTexts = [];
            var chapterMatch = cleaned.match(/"chapter"\s*:\s*\{[\s\S]*?"content"\s*:\s*\[([\s\S]*)/);
            if (chapterMatch) {
              var contentStr = chapterMatch[1];
              var textParts = contentStr.split(/"text"\s*:\s*"/);
              for (var pi = 1; pi < textParts.length; pi++) {
                var textPart = textParts[pi].replace(/"\s*[,}].*/, "").replace(/\\"/g, '"').replace(/\\n/g, "<br>");
                if (textPart.trim()) allTexts.push(textPart.trim());
              }
            }
            if (allTexts.length === 0 && cleaned.trim().length > 20) {
              var afterJson = cleaned.replace(/^\s*\{/, "");
              var simpleTexts = afterJson.split(/"text"\s*:\s*"/);
              for (var si = 1; si < simpleTexts.length; si++) {
                var st = simpleTexts[si].replace(/"\s*[,}].*/, "").replace(/\\"/g, '"').replace(/\\n/g, "<br>");
                if (st.trim().length > 10) allTexts.push(st.trim());
              }
            }
            /* зј“еӯҳе·ІжҸҗеҸ–зҡ„ж®өиҗҪ */
            _streamedParagraphs = allTexts.slice();
            /* еўһйҮҸжёІжҹ“пјҡеҸӘиҝҪеҠ ж–°ж®өиҗҪпјҢйҒҝе…Қе…ЁйҮҸжӣҝжҚўеҜјиҮҙй—ӘзғҒ */
            var currentCount = streamEl.children.length;
            var fs = state.settings.fontSize || 16;
            for (var ai = currentCount; ai < allTexts.length; ai++) {
              var paraDiv = document.createElement("div");
              paraDiv.className = "hp-stream-para";
              paraDiv.style.cssText = "font-size:" + fs + "px;line-height:1.8;margin:8px 0;color:var(--text-primary)";
              paraDiv.innerHTML = renderRichText(allTexts[ai]);
              streamEl.appendChild(paraDiv);
            }
            /* е№іж»‘ж»ҡеҠЁеҲ°еә•йғЁ */
            var contentEl = document.getElementById("hp-reader-content");
            if (contentEl) contentEl.scrollTop = contentEl.scrollHeight;
          }
        },
        function(raw) {
          debugLog("L2 stream done, raw len:" + raw.length + " first500:" + raw.substring(0, 500));
          try {
            var extractResult = stripXmlAndExtractJson(raw); var jsonStr = extractResult.json; var macroChain = extractResult.macroChain;
            debugLog("L2 has macro_chain tag:" + (raw.indexOf("<macro_chain>") >= 0) + " has_macroChain:" + !!macroChain + " macroChainLen:" + (macroChain ? macroChain.length : 0));
            if (!jsonStr) { debugLog("L2 no JSON found, using streamed paragraphs fallback"); _useStreamedFallback(summary, _streamedParagraphs, callback); return; }
            var data = JSON.parse(jsonStr);
            debugLog("L2 parsed OK, chapters:" + (data.chapters ? data.chapters.length : 0) + " hasContSummary:" + !!data.continuation_summary);
            if (data && data.continuation_summary) {
              summary.continuationSummary = data.continuation_summary;
            }
            if (data && data.content_summary) {
              /* content_summaryдјҳе…ҲпјҢзӣҙжҺҘи®ҫзҪ® */
              summary.contentSummary = data.content_summary;
            } else if (data && data.continuation_summary) {
              /* жІЎжңүcontent_summaryж—¶пјҢз”Ёcontinuation_summaryдҪңдёәcontentSummary */
              summary.contentSummary = data.continuation_summary;
            }
            if (data && data.author_notes) {
              summary.authorNotes = data.author_notes;
              debugLog("L2 author_notes: " + data.author_notes.substring(0, 80));
            }
            if (macroChain) summary._debugContext.macroChain = macroChain;
            callback(data);
          } catch(e) {
            debugLog("L2 parse error:" + e.message + ", trying raw paragraph extraction");
            var rawParagraphs = _streamedParagraphs.length > 0 ? _streamedParagraphs : extractParagraphsFromRaw(raw);
            _useStreamedFallback(summary, rawParagraphs, callback);
          }
        },
        function(e) { debugLog("L2 stream error:" + (e && e.message ? e.message : String(e)) + ", trying raw paragraph extraction"); var rawParagraphs = _streamedParagraphs.length > 0 ? _streamedParagraphs : extractParagraphsFromRaw(""); _useStreamedFallback(summary, rawParagraphs, callback); }
      );
    };
    var attachMem = shouldAttachMemory();
    var mountedIds = state.settings.mountedConversationIds || [];
    debugLog("L2 attachMem:" + attachMem + " mountedIds:" + JSON.stringify(mountedIds));
    if (attachMem && mountedIds.length > 0) { debugLog("L2 loading memories..."); loadMountedMemories(function(mt) { debugLog("L2 memories loaded, len:" + mt.length); doChat(mt.substring(0, 3000)); }); } else { debugLog("L2 skipping memory"); doChat(""); }
    } catch(e) { debugLog("L2 FATAL:" + e.message + " stack:" + (e.stack || "").substring(0, 300)); callback(null); }
  }

  function generateLayer3Comments(fullText, callback, existingComments) {
    try {
    debugLog("L3 start, fullText len:" + fullText.length + " existingComments:" + (existingComments ? existingComments.length : 0));
    var chatFn = getActiveModelPreset() ? customAiChat : aiChatStream;
    var promptSrc = (state.settings.promptLanguage === "en" && PROMPTS.layer3CommentsEN) ? PROMPTS.layer3CommentsEN : PROMPTS.layer3Comments;
    var userMsg = "\u4ee5\u4e0b\u662f\u540c\u4eba\u6587\u5185\u5bb9\uff0c\u8bf7\u751f\u6210\u8bc4\u8bba\uff1a\n\n" + fullText.substring(0, 3000);
    /* еҰӮжһңжңүе·ІжңүиҜ„и®әпјҲеҢ…жӢ¬з”ЁжҲ·иҜ„и®әпјүпјҢдј з»ҷL3и®©NPCеҸҜд»ҘеӣһеӨҚ */
    if (existingComments && existingComments.length > 0) {
      userMsg += "\n\n\u3010\u5df2\u6709\u8bc4\u8bba\u3011\n";
      for (var i = 0; i < existingComments.length; i++) {
        var ec = existingComments[i];
        userMsg += "- " + (ec.name || "\u533f\u540d") + "\uff1a" + (ec.text || "") + (ec.replyTo ? " \uff08\u56de\u590d " + ec.replyTo + "\uff09" : "") + "\n";
      }
      userMsg += "\n\u8bf7\u751f\u6210\u65b0\u7684\u8bc4\u8bba\uff0c\u53ef\u4ee5\u56de\u590d\u5df2\u6709\u8bc4\u8bba\uff0c\u4e5f\u53ef\u4ee5\u72ec\u7acb\u53d1\u8868\u3002";
    }
    chatFn([
      { role: "system", content: promptSrc },
      { role: "user", content: userMsg }
    ], 0.75,
      function(progress) { debugLog("L3 streaming... len:" + progress.length); },
      function(raw) {
        debugLog("L3 stream done, raw len:" + raw.length + " first200:" + raw.substring(0, 200));
        try {
          var extractResult = stripXmlAndExtractJson(raw); var jsonStr = extractResult.json;
            if (!jsonStr) { debugLog("L3 no JSON found"); callback([], []); return; }
          var data = JSON.parse(jsonStr);
          debugLog("L3 parsed OK, comments:" + (data.comments || []).length + " annotations:" + (data.annotations || []).length);
          callback(data.comments || [], data.annotations || []);
        } catch(e) { debugLog("L3 parse error:" + e.message + " raw500:" + raw.substring(0, 500)); callback([], []); }
      },
      function(e) { debugLog("L3 stream error:" + (e && e.message ? e.message : String(e))); callback([], []); }
    );
    } catch(e) { debugLog("L3 FATAL:" + e.message); callback([], []); }
  }

  function generateContinuation(summary, previousContent, previousSummary, feedback, callback) {
    try {
    debugLog("Cont start, title:" + (summary.title || "?"));
    var cpTag = null;
    for (var i = 0; i < state.cpTags.length; i++) { if (state.cpTags[i].id === summary.cpTagId) { cpTag = state.cpTags[i]; break; } }
    if (!cpTag && summary.cpTagName) {
      for (var i2 = 0; i2 < state.cpTags.length; i2++) { if (state.cpTags[i2].name === summary.cpTagName) { cpTag = state.cpTags[i2]; break; } }
    }
    if (!cpTag) {
      debugLog("Cont cpTag not found, using fallback");
      var cpName = summary.cp || summary.cpTagName || "";
      var parts = cpName.split(/\s*[Г—xX]\s*/);
      cpTag = {
        id: summary.cpTagId || "fallback",
        name: cpName,
        leftSide: { id: "f1", name: parts[0] || "\u89d2\u8272A", persona: "" },
        rightSide: { id: "f2", name: parts[1] || "\u89d2\u8272B", persona: "" },
        fandomTags: []
      };
    }
    var left = cpTag.leftSide || cpTag.attackSide || {};
    var right = cpTag.rightSide || cpTag.defenseSide || {};
    debugLog("Cont cpTag found, left:" + (left.name || "?") + " right:" + (right.name || "?"));
    var wordCountMin = state.settings.wordCountMin || 3000;
    var wordCountMax = state.settings.wordCountMax || 8000;
    var wordCountStr = wordCountMin + "-" + wordCountMax + "\u5b57";
    /* з»ӯеҶҷдҪҝз”ЁL2жҸҗзӨәиҜҚ */
    var promptSrc = (state.settings.promptLanguage === "en" && PROMPTS.layer2FullEN) ? PROMPTS.layer2FullEN : PROMPTS.layer2Full;
    var systemPrompt = promptSrc.replace("[WORD_COUNT_PLACEHOLDER]", wordCountStr);
    /* жһ„е»әз”ЁжҲ·ж¶ҲжҒҜпјҡз»ӯеҶҷжЁЎејҸеЈ°жҳҺ + еҹәзЎҖдҝЎжҒҜ + з»ӯеҶҷдёҠдёӢж–Ү */
    var contChapterNum = (summary.fullContent && summary.fullContent.chapters ? summary.fullContent.chapters.length : 0) + 1;
    var userMsg = ["гҖҗз»ӯеҶҷжЁЎејҸгҖ‘дҪ зҺ°еңЁжӯЈеңЁдёәе·Іжңүзҡ„еҗҢдәәж–Үз»ӯеҶҷз¬¬" + contChapterNum + "з« гҖӮиҜ·дёҘж јжүҝжҺҘеүҚж–Үзҡ„жғ…ж„ҹзҠ¶жҖҒгҖҒи§’иүІдҪҚзҪ®е’Ңеү§жғ…иө°еҗ‘пјҢдёҚеҸҜеҮәзҺ°ж— жқҘз”ұзҡ„жғ…з»Әи·іи·ғжҲ–жҖ§ж јзӘҒеҸҳгҖӮдҪ зҡ„иҫ“еҮәж јејҸдёҺйҰ–ж¬Ўз”ҹжҲҗе®Ңе…ЁдёҖиҮҙпјҡе…Ҳе®ҢжҲҗ<macro_chain>зҡ„7жӯҘжҺЁжј”пјҢеҶҚиҫ“еҮәJSONгҖӮ", "",
      "иҜ·з»ӯеҶҷд»ҘдёӢеҗҢдәәж–Үпјҡ", "",
      "- ж Үйўҳпјҡ" + summary.title, "- CPпјҡ" + (summary.cp || summary.cpTagName || ""),
      "- ж‘ҳиҰҒпјҡ" + (summary.summary || summary.excerpt || ""), "",
      "в”Ғв”Ғв”Ғ и§’иүІдәәи®ҫ в”Ғв”Ғв”Ғ",
      "е·ҰдҪҚпјҲ" + (left.name || "жңӘзҹҘ") + "пјүпјҡ", left.persona || left.bio || "ж— жҸҸиҝ°", "",
      "еҸідҪҚпјҲ" + (right.name || "жңӘзҹҘ") + "пјүпјҡ", right.persona || right.bio || "ж— жҸҸиҝ°", "",
      "в”Ғв”Ғв”Ғ еүҚж–ҮдҝЎжҒҜ в”Ғв”Ғв”Ғ"].join("\n");
    if (summary.author_note_optional) userMsg += "\n\u4f5c\u8005\u788e\u788e\u5ff5\uff1a" + summary.author_note_optional;
    /* з»ӯеҶҷзү№жңүпјҡжіЁе…ҘеүҚж–Үж‘ҳиҰҒе’ҢеҶ…е®№ */
    if (previousSummary) userMsg += "\n\u524d\u6587\u6458\u8981\uff1a" + previousSummary;
    if (previousContent) userMsg += "\n\u524d\u6587\u5185\u5bb9\uff08\u6700\u540e2000\u5b57\uff09\uff1a" + previousContent.substring(Math.max(0, previousContent.length - 2000));
    if (cpTag.fandomTags && cpTag.fandomTags.length > 0) {
      userMsg += "\n\n\u2501\u2501 \u5708\u5b50/\u4e16\u754c\u4e66\u8bbe\u5b9a \u2501\u2501\n" + cpTag.fandomTags.join("\u3001");
    }
    if (feedback && feedback.trim()) {
      userMsg += "\n\n\u2501\u2501 \u8bfb\u8005\u53cd\u9988 \u2501\u2501\n" + feedback.trim();
    }
    debugLog("Cont sysPrompt len:" + systemPrompt.length + " userMsg len:" + userMsg.length);

    var doChat = function(memText) {
      debugLog("Cont calling aiChatStream, memLen:" + (memText ? memText.length : 0));
      if (!summary._continuationContexts) summary._continuationContexts = [];
      var contCtx = {
        systemPrompt: systemPrompt,
        userMsg: userMsg + (memText ? "\n\n\u3010\u8fd1\u671f\u4e92\u52a8\u8bb0\u5fc6\uff08\u4ec5\u4f9b\u53c2\u8003\u7d20\u6750\uff09\u3011\n" + memText : ""),
        memory: memText || "(none)",
        chapterIndex: (summary.fullContent ? summary.fullContent.chapters.length : 0) + 1,
        feedback: feedback || ""
      };
      summary._continuationContexts.push(contCtx);
      var _contParagraphs = [];
      aiChatStream([
        { role: "system", content: systemPrompt },
        { role: "user", content: userMsg + (memText ? "\n\n\u3010\u8fd1\u671f\u4e92\u52a8\u8bb0\u5fc6\uff08\u4ec5\u4f9b\u53c2\u8003\u7d20\u6750\uff09\u3011\n" + memText : "") }
      ], 0.8,
        function(progress) {
          debugLog("Cont streaming... len:" + progress.length);
          /* жҸҗеҸ–ж®өиҗҪзј“еӯҳ */
          var cleaned = progress;
          cleaned = cleaned.replace(/<macro_chain>[\s\S]*?<\/macro_chain>/gi, "");
          cleaned = cleaned.replace(/<inline_chain>[\s\S]*?<\/inline_chain>/gi, "");
          cleaned = cleaned.replace(/<inline_check>[\s\S]*?<\/inline_check>/gi, "");
          cleaned = cleaned.replace(/<macro_cot>[\s\S]*?<\/macro_cot>/gi, "");
          cleaned = cleaned.replace(/<system_execution_directive>[\s\S]*?<\/system_execution_directive>/gi, "");
          cleaned = cleaned.replace(/<!--[\s\S]*?-->/g, "");
          cleaned = cleaned.replace(/<[^>]+>/g, "");
          var allTexts = [];
          var chapterMatch = cleaned.match(/"chapter"\s*:\s*\{[\s\S]*?"content"\s*:\s*\[([\s\S]*)/);
          if (chapterMatch) {
            var textParts = chapterMatch[1].split(/"text"\s*:\s*"/);
            for (var pi = 1; pi < textParts.length; pi++) {
              var tp = textParts[pi].replace(/"\s*[,}].*/, "").replace(/\\"/g, '"').replace(/\\n/g, "\n");
              if (tp.trim()) allTexts.push(tp.trim());
            }
          }
          if (allTexts.length === 0 && cleaned.trim().length > 20) {
            var simpleTexts = cleaned.replace(/^\s*\{/, "").split(/"text"\s*:\s*"/);
            for (var si = 1; si < simpleTexts.length; si++) {
              var st = simpleTexts[si].replace(/"\s*[,}].*/, "").replace(/\\"/g, '"').replace(/\\n/g, "\n");
              if (st.trim().length > 10) allTexts.push(st.trim());
            }
          }
          _contParagraphs = allTexts.slice();
        },
        function(raw) {
          debugLog("Cont stream done, raw len:" + raw.length + " first200:" + raw.substring(0, 200));
          try {
            var extractResult = stripXmlAndExtractJson(raw); var jsonStr = extractResult.json; var contMacroChain = extractResult.macroChain;
            debugLog("Cont has macro_chain:" + (raw.indexOf("<macro_chain>") >= 0) + " macroChainLen:" + (contMacroChain ? contMacroChain.length : 0));
            if (!jsonStr) { debugLog("Cont no JSON found, trying raw extraction"); var contP = _contParagraphs.length > 0 ? _contParagraphs : extractParagraphsFromRaw(raw); _useStreamedFallback(summary, contP, callback); return; }
            var data = JSON.parse(jsonStr);
            debugLog("Cont parsed OK, hasContent:" + !!(data.content || data.text));
            /* дҝқеӯҳз»ӯеҶҷзҡ„macroChainеҲ°debugContext */
            if (contMacroChain) {
              if (!summary._continuationContexts) summary._continuationContexts = [];
              var lastCont = summary._continuationContexts.length > 0 ? summary._continuationContexts[summary._continuationContexts.length - 1] : null;
              if (lastCont) lastCont.macroChain = contMacroChain;
            }
            callback(data);
          } catch(e) { debugLog("Cont parse error:" + e.message + ", trying raw extraction"); var contP2 = _contParagraphs.length > 0 ? _contParagraphs : extractParagraphsFromRaw(raw); _useStreamedFallback(summary, contP2, callback); }
        },
        function(e) { debugLog("Cont stream error:" + (e && e.message ? e.message : String(e)) + ", trying raw extraction"); var contP3 = _contParagraphs.length > 0 ? _contParagraphs : extractParagraphsFromRaw(""); _useStreamedFallback(summary, contP3, callback); }
      );
    };
    var attachMem = shouldAttachMemory();
    var mountedIds = state.settings.mountedConversationIds || [];
    debugLog("Cont attachMem:" + attachMem + " mountedIds:" + JSON.stringify(mountedIds));
    if (attachMem && mountedIds.length > 0) { debugLog("Cont loading memories..."); loadMountedMemories(function(mt) { debugLog("Cont memories loaded, len:" + mt.length); doChat(mt.substring(0, 3000)); }); } else { debugLog("Cont skipping memory"); doChat(""); }
    } catch(e) { debugLog("Cont FATAL:" + e.message + " stack:" + (e.stack || "").substring(0, 300)); callback(null); }
  }

  function generateExploreTags(callback) {
    try {
    debugLog("Explore start, tropeTags:" + state.tropeTags.length + " cpTags:" + state.cpTags.length + " fandomTags:" + state.fandomTags.length);
    var existingNames = [];
    for (var i = 0; i < state.tropeTags.length; i++) existingNames.push(state.tropeTags[i].name);
    for (var j = 0; j < state.cpTags.length; j++) existingNames.push(state.cpTags[j].name);
    for (var k = 0; k < state.fandomTags.length; k++) existingNames.push(state.fandomTags[k].name);
    var cpInspiration = "";
    if (state.cpTags.length > 0) {
      var sampleCount = Math.min(3, state.cpTags.length);
      var shuffledCp = state.cpTags.slice();
      for (var si = shuffledCp.length - 1; si > 0; si--) { var sj = Math.floor(Math.random() * (si + 1)); var tmp = shuffledCp[si]; shuffledCp[si] = shuffledCp[sj]; shuffledCp[sj] = tmp; }
      var sampled = shuffledCp.slice(0, sampleCount);
      var cpNames = [];
      for (var ci = 0; ci < sampled.length; ci++) cpNames.push(sampled[ci].name);
      cpInspiration = "\n\n\u7528\u6237\u5173\u6ce8\u7684CP\uff08\u53ef\u4f5c\u4e3a\u7075\u611f\u53c2\u8003\uff09\uff1a" + cpNames.join("\u3001");
    }
    var excludeList = existingNames.length > 0 ? "\n\n\u7528\u6237\u5df2\u6709\u6807\u7b7e\uff08\u7edd\u5bf9\u4e0d\u53ef\u91cd\u590d\uff09\uff1a" + existingNames.join("\u3001") : "";
    debugLog("Explore calling aiChatStream, excludeCount:" + existingNames.length);
    var chatFn = getActiveModelPreset() ? customAiChat : aiChatStream;
    debugLog("Explore using chatFn: " + (getActiveModelPreset() ? "customAiChat (preset model: " + getActiveModelPreset().model + ")" : "aiChatStream (roche built-in)"));
    chatFn([
      { role: "system", content: PROMPTS.exploreTags },
      { role: "user", content: "\u8bf7\u751f\u6210\u540c\u4eba\u6807\u7b7e\u4f9b\u7528\u6237\u63a2\u7d22\u3002" + excludeList + cpInspiration }
    ], 0.9,
      function(progress) { debugLog("Explore streaming... len:" + progress.length); },
      function(raw) {
        debugLog("Explore stream done, raw len:" + raw.length + " first200:" + raw.substring(0, 200));
        try {
          var extractResult = stripXmlAndExtractJson(raw); var jsonStr = extractResult.json;
            if (!jsonStr) { debugLog("Explore no JSON found in raw response, raw100:" + raw.substring(0, 100)); callback([]); return; }
          var data = JSON.parse(jsonStr);
          debugLog("Explore parsed OK, tags:" + (data.tags || []).length);
          callback(data.tags || []);
        } catch(e) { debugLog("Explore parse error:" + e.message + " raw500:" + raw.substring(0, 500)); callback([]); }
      },
      function(e) {
        debugLog("Explore stream error: " + (e && e.message ? e.message : String(e)));
        debugLog("Explore error details: name=" + (e ? e.name : "null") + " stack=" + (e && e.stack ? e.stack.substring(0, 300) : "n/a"));
        callback([]);
      }
    );
    } catch(e) { debugLog("Explore FATAL:" + e.message); callback([]); }
  }

  /* в”Җв”Җв”Җ CSS ж ·ејҸ в”Җв”Җв”Җ */
